  _load() {
    let buffer = '';

    if (!this.path) {
      process.nextTick(() => {
        this.emit('load', 0);
      });
      return;
    }

    this._readStream = fs.createReadStream(this.path, {
      encoding: 'utf-8',
      flags: 'r',
    });

